VALUES
  ('judicial-cf446b4c-moex-00104', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於數罪併罰，下列敘述何者正確？', '["宣告多數無期徒刑者，不問情狀，一律終身監禁，不得假釋", "宣告多數褫奪公權者，合併計算期間而執行之", "宣告多數罰金者，從一重處斷", "宣告多數有期徒刑時，定執行刑不得逾30年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00105', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關刑之減輕，下列敘述何者正確？', '["滿80歲人犯罪，本刑為死刑或無期徒刑者，減輕其刑", "犯罪之情狀顯可憫恕，認科以最高度刑仍嫌過重者，得酌量減輕其刑", "依法律加重或減輕者，不得再依刑法第59條之規定酌量減輕其刑", "無期徒刑減輕者，為15年以下10年以上有期徒刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00106', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關緩刑之敘述，下列何者錯誤？', '["行為人受3年以下有期徒刑之宣告時，法院得宣告緩刑", "若在緩刑期間內故意犯他罪而受7個月有期徒刑之宣告確定時，得撤銷緩刑", "緩刑期滿未經撤銷時，刑之宣告失其效力", "在宣告緩刑時得命犯罪行為人向被害人道歉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00107', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於罪刑法定原則敘述，下列何者錯誤？', '["絕對不定期刑之規定違反罪刑法定原則", "依學說見解，罪刑法定原則亦許可有利行為人之類推適用", "超法規阻卻違法事由之適用違反罪刑法定原則", "罪刑法定原則包括罪刑明確性之要求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00108', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲犯擄人勒贖罪，取得贖金後旋即偷渡出境而被通緝，有關時效之敘述，下列何者錯誤？', '["擄人勒贖罪之追訴時效為30年", "該罪之時效自犯罪成立之日起算", "若甲擄人勒贖致人於死，無追訴權消滅問題", "追訴權之時效因甲逃匿遭通緝而停止進行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00109', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於刑法第132條洩漏國防以外秘密罪，下列敘述何者錯誤？', '["負責採購之公務員甲於採購前洩漏預定單價予廠商乙，構成刑法第132條第1項之罪", "檢察官甲洩漏偵查中之刑事案件資料予不相干之第三人乙，構成刑法第132條第1項之罪", "員警甲洩漏因其公務而知悉之民眾乙戶籍資料，因僅涉及個人資訊，不成立刑法第132條第1項之罪", "員警甲洩漏其所掌管之刑事案件筆錄資料予記者乙，構成刑法第132條第1項之罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00110', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '關於妨害公務罪，下列敘述何者錯誤？', '["對於公務員依法執行職務時施強暴，係指公務員開始實行其職務時至其行為終了時止，若已經執行職務 完畢，不成立妨害公務罪", "對於公務員依法執行職務時施強暴，係指公務員開始實行其職務時至其行為終了時止，若尚未開始執行 職務，不成立妨害公務罪", "甲對於執行職務之警察乙施以脅迫而妨害公務，但乙沒有理會，繼續執行職務，甲成立妨害公務罪未遂犯", "甲對於執行職務之警察乙施以脅迫而妨害公務，一經實施，妨害公務罪即成立，對於執行職務，已否發 生妨害之結果，在所不問"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00111', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '依通說見解，下列何者非屬刑法第161條第2項之「拘禁處所」？', '["監獄", "看守所", "警察民眾服務中心", "民事管收所"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00112', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '甲對時局不滿在網站上公開發文，謊稱其已在某未指名的捷運站內放置炸彈，目的是要警告某立法委員， 該貼文遭網友大量轉傳，造成人心惶惶。甲隨後因觸犯刑法第151條恐嚇公眾罪遭移送法辦。下列敘述何 者正確？', '["甲雖係謊稱，但仍屬恐嚇", "甲僅係警告某立法委員，尚不符合以加害生命之事恐嚇公眾", "甲警告的對象係某立法委員而非公眾，故行為客體並非本罪規範對象", "雖人心惶惶，但因甲並未放置炸彈，故不該當「致生危害於公安」要件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00113', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', 'A殺死B，目擊證人甲誤以為是C殺死B，於法院審判時，證人甲具結後陳述「C殺死B」，甲之刑事責任 為何？', '["過失偽證罪", "故意偽證罪", "誣告罪", "甲不成立犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:21+00:00", "source_pdf_sha1": "a525ee14afef", "answer_pdf_sha1": "fa3e7a8162d0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
